  "verses": [
    {
      "n": 20,
      "column": "left",
      "text": "Tad buhs tam Preesteram\nkohs ar to Pirimojo Maiſi par weenu\nRustinaschanas - Uppuri\npreekſch ta KUNGA / lihſ ar\nteen diwi Jehreem rustinaht/teem\nbuhs tam KUNGAM ſwehteein\nbuht / un peederr tam Pree-\nsteram."
    },
    {
      "n": 21,
      "column": "left",
      "text": "Un jums buhs to paſchu\nDeenn iſſaukt / weenu ſwehtu\nSasauſchana buhs jums tur-\nreht/ne kahdu Kalpoſchanas-Dar-\nbuhs jums darriht / tas lai\nirr weens Likkums wiſſôs juhſôs\nDsihwoktôs pee juhſu Pehznah-\nkameem muhschan."
    },
    {
      "n": 22,
      "column": "left",
      "text": "Rad juhs nu juhſas Sem-\nmes Augtus ptaufet / tad ne\nbuhs jums tawa Tihryma Stuh-\nri tawa Ptaufchana wiſſai no-\npfaut/neds tawusAugtus ſchky-\nſti falaffiht/preekſch ta Nabbaga/\nun preekſch ta Sweschineeka buhs\njums tohs painest / Es eſmu tas\nKUNGS juhſu Deewg."
    },
    {
      "n": 23,
      "column": "left",
      "text": "Un tas KUNGS runnaja\nus Mohſu/ un fazzija:"
    },
    {
      "n": 24,
      "column": "left",
      "text": "Runna us Israëla Behr-\nneem/ un ſakki: ſeptitâ Mehnefi\npirinâ Mehnes Deena laid jums\nweena Duffefchana irr/tahs Tan-\nrefschanas Peeminneschana / wee-\nna ſwehta Sasauſchana."
    },
    {
      "n": 25,
      "column": "left",
      "text": "Ne kahdu Kalpoſchanas-\nDarbu buhs jums darriht / bet\njuhs buhs tam KUNGAM ar\nUgguni uppureht."
    },
    {
      "n": 26,
      "column": "left",
      "text": "Un tas KUNGS runna-\nja us Mohſu/ un fazzija:"
    },
    {
      "n": 27,
      "column": "left",
      "text": "Bet deſmitâ Deenaſchin-"
    },
    {
      "n": 28,
      "column": "right",
      "text": "Un tanni Deena ne buhs\njums ne kahdu Darbu darriht/ jo\nta irr ta Salihdsinaschanas-Dee-\nna/ ka juhs falihdsinati tohpat /\nta KUNGA juhſu Deewa\nPreekſcha."
    },
    {
      "n": 29,
      "column": "right",
      "text": "Jo ikweens/ kas tai Dee-\nnâ tawu Meeſu ne mehrde/ tas\ntaps iſdeldehts no ſaweem Lau-\ndim."
    },
    {
      "n": 30,
      "column": "right",
      "text": "Un ikweens/ kas tai Dee-\nnâ kahdu Darbu darrihs/ to pa-\nschu nomaitaschu es no ſawu\nLauschu Widdus."
    },
    {
      "n": 31,
      "column": "right",
      "text": "Ne kahdu Darbu buhs\njums darriht/ laid tas irr weens\nLikkums pee juhſeim Pehznah-\nkameem muhschan/ wiſſôs juh-\nfôs Dsihwoktôs."
    },
    {
      "n": 32,
      "column": "right",
      "text": "Lai ſcht jums ta ( leela )\nDuffeschanas-Deena irr / tur\nbuhs jums juhſas Mecfas mehr-\ndeht/ no ta dewita Mehnes Wak-\nkara/ no Wakkara lihſ Wakka-\nram buhs jums juhſu Duffefcha-\nnas-Deenu turreht."
    },
    {
      "n": 33,
      "column": "right",
      "text": "Un tas KUNGS runna-\nja us Mohsu/ un fazzija:"
    },
    {
      "n": 34,
      "column": "right",
      "text": "Runna us Israëla Behr-\nneem/ un ſakki: peektapadeſmitâ\nDeenaſchinni ſeptitâ Mehneti\nbuhs tee Leewenu Swehtki/ ſep-\ntin Deenas tam KUNGAM."
    },
    {
      "n": 35,
      "column": "right",
      "text": "Pirma Deena laid weena\nſwehta"
    }
  ],
  "confidence": "high",
